class Solution:
    def maxGCDScore(self, nums: List[int], k: int) -> int:
        n = len(nums)
        max_score = 0
        gcd_prefix = [0] * (n + 1)
        gcd_suffix = [0] * (n + 1)
        for i in range(n):
            gcd_prefix[i + 1] = math.gcd(gcd_prefix[i], nums[i])
        for i in range(n - 1, -1, -1):
            gcd_suffix[i] = math.gcd(gcd_suffix[i + 1], nums[i])
        for i in range(n):
            left_gcd = gcd_prefix[i]
            right_gcd = gcd_suffix[i + 1]
            curr_gcd = math.gcd(left_gcd, right_gcd, nums[i] * 2)
            max_score = max(max_score, curr_gcd * 1)
            if i > 0:
                max_score = max(max_score, math.gcd(left_gcd, nums[i] * 2) * i)
            if i < n - 1:
                max_score = max(max_score, math.gcd(right_gcd, nums[i] * 2) * (n - i))
        for length in range(2, min(k + 1, n + 1)):
            for i in range(n - length + 1):
                gcd_val = nums[i]
                for j in range(i, i + length):
                    gcd_val = math.gcd(gcd_val, nums[j])
                max_score = max(max_score, gcd_val * length)
        for i in range(n):
            if k > 0:
                max_score = max(max_score, nums[i] * 2)
                k -= 1
        return max_score
